def fact_rec(n):
    if n <= 1:
        return 1
    return n * fact_rec(n - 1)

def palindrome(text):
    i, j = 0, len(text) - 1
    while i < j:
        if text[i] != text[j]:
            return False
        i += 1
        j -= 1
    return True

