def binary_search(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        m = (left + right) // 2
        if arr[m] == target:
            return m
        elif arr[m] < target:
            left = m + 1
        else:
            right = m - 1
    return -1

